    return pn.Column(
        pn.widgets.Button(name="Toggle", on_click=state.change),
        cond(
            state.param.show,
            pn.pane.Str("Text 1", styles={"color": "blue"}),
            pn.pane.Str("Text 2", styles={"color": "red"}),
        ),
        state.param.show
    )

cond_example().servable()
