## Workaround

For someone in need of a workaround to be able to copy paste from Excel you can use something like below.

To use

- Copy an area from Excel
- Click on the gray area in the app to select it
- Press CTRL+V to paste
- Verify data is in the table

```python
import panel as pn
import param
from io import StringIO
import pandas as pd

pn.extension("tabulator")


class PasteFromXLSX(pn.custom.JSComponent):
    """This function will catch data pasted from Excel
    and send it to the server"""

    value = param.Parameter()
    data = param.DataFrame()

    _esm = """
export function render({ model, el }) {
    const root = document.createElement('div');
    root.classList.add('paste-area');
    /* root.innerHTML=`<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 512 512"><!--!Font Awesome Free 6.6.0 by @fontawesome - https://fontawesome.com License - https://fontawesome.com/license/free Copyright 2024 Fonticons, Inc.--><path d="M104.6 48L64 48C28.7 48 0 76.7 0 112L0 384c0 35.3 28.7 64 64 64l96 0 0-48-96 0c-8.8 0-16-7.2-16-16l0-272c0-8.8 7.2-16 16-16l16 0c0 17.7 14.3 32 32 32l72.4 0C202 108.4 227.6 96 256 96l62 0c-7.1-27.6-32.2-48-62-48l-40.6 0C211.6 20.9 188.2 0 160 0s-51.6 20.9-55.4 48zM144 56a16 16 0 1 1 32 0 16 16 0 1 1 -32 0zM448 464l-192 0c-8.8 0-16-7.2-16-16l0-256c0-8.8 7.2-16 16-16l140.1 0L464 243.9 464 448c0 8.8-7.2 16-16 16zM256 512l192 0c35.3 0 64-28.7 64-64l0-204.1c0-12.7-5.1-24.9-14.1-33.9l-67.9-67.9c-9-9-21.2-14.1-33.9-14.1L256 128c-35.3 0-64 28.7-64 64l0 256c0 35.3 28.7 64 64 64z"/></svg>` */

    root.addEventListener('paste', (event) => {
        const pastedData = event.clipboardData.getData('text');
        model.value = pastedData;
    });
    el.appendChild(root);
}
"""

    _stylesheets = [
        """
    .paste-area{
        height: 100%;
        width: 100%;
        padding:20%;
        background: silver;
    }
    """
    ]

    @param.depends("value", watch=True, on_init=True)
    def value_as_dataframe(self):
        if not self.value:
            self.data = pd.DataFrame({0: [20]})
        else:
            self.data = pd.read_csv(StringIO(self.value), sep="\t", header=None)


paste = PasteFromXLSX(height=60, width=50)

table = pn.widgets.Tabulator(paste.param.data)

pn.Row(paste, table).servable()
